const https = require('https');

function nocoRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'nocodb.pressco21.com',
      path: '/api/v1/db/data/noco/' + $env.NOCODB_PROJECT_ID + path,
      method: method,
      headers: {
        'xc-token': $env.NOCODB_API_TOKEN,
        'Content-Type': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); } catch(e) { resolve(data); }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

const body = $input.first().json.body || {};
const action = body.action;

try {
  if (action === 'getSchedules') {
    const classId = body.class_id;
    if (!classId) return [{json: {success: false, message: 'class_id required', statusCode: 400}}];
    const result = await nocoRequest('GET', '/mschd3d81ad88fb?where=(class_id,eq,' + classId + ')~and(status,eq,active)&sort=schedule_date,schedule_time&limit=100');
    const list = result.list || [];
    const schedules = list.map(s => ({
      schedule_id: s.schedule_id, class_id: s.class_id,
      schedule_date: s.schedule_date, schedule_time: s.schedule_time,
      capacity: s.capacity || 8, booked_count: s.booked_count || 0,
      remaining: (s.capacity || 8) - (s.booked_count || 0), status: s.status
    }));
    return [{json: {success: true, data: {schedules, total: schedules.length}, statusCode: 200}}];

  } else if (action === 'addSchedule') {
    const {member_id, class_id, schedule_date, schedule_time, capacity} = body;
    if (!member_id || !class_id || !schedule_date || !schedule_time)
      return [{json: {success: false, message: 'missing required fields', statusCode: 400}}];
    if (!/^\d{4}-\d{2}-\d{2}$/.test(schedule_date))
      return [{json: {success: false, message: 'date format: YYYY-MM-DD', statusCode: 400}}];
    if (!/^\d{2}:\d{2}$/.test(schedule_time))
      return [{json: {success: false, message: 'time format: HH:MM', statusCode: 400}}];
    const today = new Date().toISOString().split('T')[0];
    if (schedule_date < today)
      return [{json: {success: false, message: 'past date not allowed', statusCode: 400}}];
    const cap = parseInt(capacity, 10) || 8;
    if (cap < 1 || cap > 50)
      return [{json: {success: false, message: 'capacity 1-50', statusCode: 400}}];

    // 파트너 인증
    const partners = await nocoRequest('GET', '/mp8t0yq15cabmj4?where=(member_id,eq,' + member_id + ')~and(status,eq,active)&limit=1');
    if (!partners.list || partners.list.length === 0)
      return [{json: {success: false, message: 'not an active partner', statusCode: 403}}];
    const partner = partners.list[0];

    // 클래스 소유 확인
    const classes = await nocoRequest('GET', '/mpvsno4or6asbxk?where=(class_id,eq,' + class_id + ')~and(partner_code,eq,' + partner.partner_code + ')&limit=1');
    if (!classes.list || classes.list.length === 0)
      return [{json: {success: false, message: 'you do not own this class', statusCode: 403}}];

    // 중복 확인
    const dups = await nocoRequest('GET', '/mschd3d81ad88fb?where=(class_id,eq,' + class_id + ')~and(schedule_date,eq,' + schedule_date + ')~and(schedule_time,eq,' + schedule_time + ')~and(status,ne,cancelled)&limit=1');
    if (dups.list && dups.list.length > 0)
      return [{json: {success: false, message: 'duplicate schedule exists', statusCode: 409}}];

    // schedule_id 생성
    const dateStr = schedule_date.replace(/-/g, '');
    const rand = String(Math.floor(Math.random() * 99) + 1).padStart(2, '0');
    const scheduleId = 'SCH_' + dateStr + '_' + rand;

    // INSERT
    const created = await nocoRequest('POST', '/mschd3d81ad88fb', {
      schedule_id: scheduleId, class_id, schedule_date, schedule_time,
      capacity: cap, booked_count: 0, status: 'active'
    });

    return [{json: {success: true, message: 'schedule created', data: {
      schedule_id: scheduleId, class_id, schedule_date, schedule_time, capacity: cap
    }, statusCode: 201}}];

  } else if (action === 'deleteSchedule') {
    const {member_id, schedule_id} = body;
    if (!member_id || !schedule_id)
      return [{json: {success: false, message: 'missing required fields', statusCode: 400}}];

    // 일정 조회
    const schResult = await nocoRequest('GET', '/mschd3d81ad88fb?where=(schedule_id,eq,' + schedule_id + ')&limit=1');
    if (!schResult.list || schResult.list.length === 0)
      return [{json: {success: false, message: 'schedule not found', statusCode: 404}}];

    const sch = schResult.list[0];
    const hasBookings = (sch.booked_count || 0) > 0;

    // status → cancelled
    await nocoRequest('PATCH', '/mschd3d81ad88fb/' + sch.Id, { status: 'cancelled' });

    return [{json: {success: true, message: 'schedule cancelled', data: {
      schedule_id: sch.schedule_id,
      warning: hasBookings ? (sch.booked_count + ' students have bookings') : null
    }, statusCode: 200}}];

  } else {
    return [{json: {success: false, message: 'Unknown action. Use addSchedule, deleteSchedule, getSchedules', statusCode: 400}}];
  }
} catch(e) {
  return [{json: {success: false, message: 'Internal error: ' + e.message, statusCode: 500}}];
}
